Here are the public test cases for feature1_1_directory_create:
{
  "description": "Create directories. A directory can be created at a path whose parent already exists; creating it recursively also materializes any missing ancestor directories. Creating a directory that already exists as a directory is a no-op success. The created directory's path is echoed back.",
  "cases": [
    {
      "input": {
        "ops": [
          {
            "op": "create_directory",
            "path": "/foo"
          },
          {
            "op": "exists",
            "path": "/foo",
            "as": "directory"
          }
        ]
      },
      "expected_output": "created_directory=/foo\nexists=true\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "create_directory",
            "path": "/a/b/c",
            "recursive": true
          },
          {
            "op": "exists",
            "path": "/a/b/c",
            "as": "directory"
          }
        ]
      },
      "expected_output": "created_directory=/a/b/c\nexists=true\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "create_directory",
            "path": "/a/b/c"
          }
        ]
      },
      "expected_output": "error=no_such_file_or_directory\n"
    }
  ]
}

Here are the public test cases for feature1_2_directory_list:
{
  "description": "List the immediate children of a directory, or recursively list all descendants. Each entry is reported as its kind (file/directory/link) and its path. Entries are emitted in a stable, lexicographically sorted order and the total count is reported first.",
  "cases": [
    {
      "input": {
        "ops": [
          {
            "op": "create_directory",
            "path": "/d"
          },
          {
            "op": "create_file",
            "path": "/d/b"
          },
          {
            "op": "create_file",
            "path": "/d/a"
          },
          {
            "op": "create_directory",
            "path": "/d/sub"
          },
          {
            "op": "list",
            "path": "/d"
          }
        ]
      },
      "expected_output": "created_directory=/d\ncreated_file=/d/b\ncreated_file=/d/a\ncreated_directory=/d/sub\nentry_count=3\nentry=directory:/d/sub\nentry=file:/d/a\nentry=file:/d/b\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "create_directory",
            "path": "/a/b/c",
            "recursive": true
          },
          {
            "op": "create_file",
            "path": "/a/b/c/f.txt"
          },
          {
            "op": "list",
            "path": "/a",
            "recursive": true
          }
        ]
      },
      "expected_output": "created_directory=/a/b/c\ncreated_file=/a/b/c/f.txt\nentry_count=3\nentry=directory:/a/b\nentry=directory:/a/b/c\nentry=file:/a/b/c/f.txt\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "create_directory",
            "path": "/empty"
          },
          {
            "op": "list",
            "path": "/empty"
          }
        ]
      },
      "expected_output": "created_directory=/empty\nentry_count=0\n"
    }
  ]
}

Here are the public test cases for feature1_3_directory_delete:
{
  "description": "Delete a directory. A non-recursive delete succeeds only when the directory is empty; deleting a non-empty directory non-recursively fails with a directory-not-empty category. A recursive delete removes the directory and all of its contents. The deleted path is echoed back.",
  "cases": [
    {
      "input": {
        "ops": [
          {
            "op": "create_directory",
            "path": "/d"
          },
          {
            "op": "delete",
            "path": "/d",
            "as": "directory"
          },
          {
            "op": "exists",
            "path": "/d",
            "as": "directory"
          }
        ]
      },
      "expected_output": "created_directory=/d\ndeleted=/d\nexists=false\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "create_directory",
            "path": "/foo"
          },
          {
            "op": "create_file",
            "path": "/foo/x"
          },
          {
            "op": "delete",
            "path": "/foo",
            "as": "directory"
          }
        ]
      },
      "expected_output": "created_directory=/foo\ncreated_file=/foo/x\nerror=directory_not_empty\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "create_directory",
            "path": "/foo"
          },
          {
            "op": "create_file",
            "path": "/foo/x"
          },
          {
            "op": "delete",
            "path": "/foo",
            "as": "directory",
            "recursive": true
          },
          {
            "op": "exists",
            "path": "/foo",
            "as": "directory"
          }
        ]
      },
      "expected_output": "created_directory=/foo\ncreated_file=/foo/x\ndeleted=/foo\nexists=false\n"
    }
  ]
}

