Here are the public test cases for feature2_1_file_text:
{
  "description": "Write a string to a file and read it back as text. Writing reports the number of bytes (UTF-8 encoded) written; reading returns the JSON-quoted text content. Reading a zero-byte file yields an empty string.",
  "cases": [
    {
      "input": {
        "ops": [
          {
            "op": "create_file",
            "path": "/foo/bar.txt",
            "recursive": true
          },
          {
            "op": "write",
            "path": "/foo/bar.txt",
            "text": "hello"
          },
          {
            "op": "read",
            "path": "/foo/bar.txt"
          },
          {
            "op": "length",
            "path": "/foo/bar.txt"
          }
        ]
      },
      "expected_output": "created_file=/foo/bar.txt\nwrote_bytes=5\ntext=\"hello\"\nlength=5\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "create_file",
            "path": "/e"
          },
          {
            "op": "read",
            "path": "/e"
          }
        ]
      },
      "expected_output": "created_file=/e\ntext=\"\"\n"
    },
    {
      "input": {
        "ops": [
          {
            "op": "write",
            "path": "/u.txt",
            "text": "héllo"
          },
          {
            "op": "read",
            "path": "/u.txt"
          },
          {
            "op": "length",
            "path": "/u.txt"
          }
        ]
      },
      "expected_output": "wrote_bytes=6\ntext=\"héllo\"\nlength=6\n"
    }
  ]
}

